// Input validation and sanitization
function validateMessage(message) {
  if (!message || typeof message !== 'object') {
    throw new Error('Invalid message: must be a JSON object');
  }

  if (!message.type || typeof message.type !== 'string') {
    throw new Error('Invalid message: missing or invalid "type" field');
  }

  if (!ALLOWED_MESSAGE_TYPES.includes(message.type)) {
    throw new Error(`Invalid message type: "${message.type}" is not allowed`);
  }

  if (!message.payload || typeof message.payload !== 'object') {
    throw new Error('Invalid message: missing or invalid "payload" field');
  }

  // Sanitize string fields in payload to prevent injection
  const sanitizedPayload = sanitizePayload(message.payload);

  return {
    type: message.type,
    payload: sanitizedPayload,
    correlationId: message.correlationId || uuidv4(),
    timestamp: message.timestamp || new Date().toISOString(),
  };
}

function sanitizePayload(payload) {
  const sanitized = {};
  for (const [key, value] of Object.entries(payload)) {
    // Only allow alphanumeric keys with underscores
    if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(key)) {
      throw new Error(`Invalid payload key: "${key}"`);
    }

    if (typeof value === 'string') {
      // Prevent SQL injection by rejecting dangerous patterns
      if (/[;'"\\]|--|\bDROP\b|\bDELETE\b|\bINSERT\b|\bUPDATE\b|\bEXEC\b/i.test(value) && value.length > 500) {
        throw new Error(`Potentially dangerous value for key: "${key}"`);
      }
      sanitized[key] = value.trim();
    } else if (typeof value === 'number' || typeof value === 'boolean') {
      sanitized[key] = value;
    } else if (value === null) {
      sanitized[key] = null;
    } else if (Array.isArray(value)) {
      sanitized[key] = value.map((item) => {
        if (typeof item === 'string') return item.trim();
        if (typeof item === 'number' || typeof item === 'boolean') return item;
        return null;
      }).filter(item => item !== null);
    } else if (typeof value === 'object') {
      sanitized[key] = sanitizePayload(value);
    }
  }
  return sanitized;
}

