// Event logging helper
async function logEvent(correlationId, eventType, entityId, payload) {
  try {
    const query = `
      INSERT INTO event_log (id, correlation_id, event_type, entity_id, payload, created_at)
      VALUES ($1, $2, $3, $4, $5, NOW())
    `;
    await pool.query(query, [uuidv4(), correlationId, eventType, entityId, JSON.stringify(payload)]);
  } catch (error) {
    logger.error('Failed to log event', { correlationId, eventType, error: error.message });
  }
}

// Process a single message
async function processMessage(msg, channel) {
  const startTime = Date.now();
  let parsedMessage;

  try {
    // Parse the message content
    const content = msg.content.toString();
    parsedMessage = JSON.parse(content);

    // Validate and sanitize the message
    const validatedMessage = validateMessage(parsedMessage);
    const { type, payload, correlationId } = validatedMessage;

    logger.info('Processing message', {
      correlationId,
      type,
      messageId: msg.properties.messageId,
    });

    // Get the handler for this message type
    const handler = messageHandlers[type];
    if (!handler) {
      throw new Error(`No handler found for message type: ${type}`);
    }

    // Execute the handler
    const result = await handler(payload, correlationId);

    const processingTime = Date.now() - startTime;
    logger.info('Message processed successfully', {
      correlationId,
      type,
      processingTimeMs: processingTime,
    });

    // Acknowledge the message
    channel.ack(msg);
    return result;
  } catch (error) {
    const processingTime = Date.now() - startTime;
    const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;

    logger.error('Message processing failed', {
      error: error.message,
      stack: error.stack,
      messageType: parsedMessage?.type,
      retryCount,
      processingTimeMs: processingTime,
    });

    // Retry logic
    if (retryCount < config.rabbitmq.retryLimit) {
      // Republish with incremented retry count
      const headers = { ...msg.properties.headers, 'x-retry-count': retryCount + 1 };
      channel.publish('', config.rabbitmq.queue, msg.content, {
        ...msg.properties,
        headers,
      });
      channel.ack(msg);
      logger.warn('Message requeued for retry', { retryCount: retryCount + 1 });
    } else {
      // Send to dead letter queue
      try {
        const dlqMessage = JSON.stringify({
          originalMessage: parsedMessage || msg.content.toString(),
          error: error.message,
          retryCount,
          failedAt: new Date().toISOString(),
        });
        channel.sendToQueue(config.rabbitmq.deadLetterQueue, Buffer.from(dlqMessage), {
          persistent: true,
        });
      } catch (dlqError) {
        logger.error('Failed to send to DLQ', { error: dlqError.message });
      }
      channel.ack(msg);
      logger.error('Message sent to dead letter queue after max retries', { retryCount });
    }
  }
}

// Initialize database tables
async function initializeDatabase() {
  const client = await pool.connect();
  try {
    await client.query(`
      CREATE TABLE IF NOT EXISTS users (
        id VARCHAR(255) PRIMARY KEY,
        email VARCHAR(255) UNIQUE,
        name VARCHAR(255),
        role VARCHAR(50) DEFAULT 'user',
        status VARCHAR(50) DEFAULT 'active',
        deleted_at TIMESTAMP,
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS orders (
        id VARCHAR(255) PRIMARY KEY,
        user_id VARCHAR(255),
        total_amount DECIMAL(10,2),
        currency VARCHAR(10) DEFAULT 'USD',
        status VARCHAR(50) DEFAULT 'pending',
        cancel_reason TEXT,
        metadata JSONB DEFAULT '{}',
        completed_at TIMESTAMP,
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS order_items (
        id VARCHAR(255) PRIMARY KEY,
        order_id VARCHAR(255) REFERENCES orders(id),
        product_id VARCHAR(255),
        quantity INTEGER,
        unit_price DECIMAL(10,2),
        created_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS inventory (
        product_id VARCHAR(255) PRIMARY KEY,
        quantity INTEGER DEFAULT 0,
        updated_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS notifications (
        id VARCHAR(255) PRIMARY KEY,
        user_id VARCHAR(255),
        channel VARCHAR(50),
        subject TEXT,
        body TEXT,
        template VARCHAR(255),
        status VARCHAR(50) DEFAULT 'queued',
        created_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS analytics_events (
        id VARCHAR(255) PRIMARY KEY,
        event_name VARCHAR(255),
        user_id VARCHAR(255),
        session_id VARCHAR(255),
        properties JSONB DEFAULT '{}',
        created_at TIMESTAMP DEFAULT NOW()
      );

      CREATE TABLE IF NOT EXISTS event_log (
        id VARCHAR(255) PRIMARY KEY,
        correlation_id VARCHAR(255),
        event_type VARCHAR(255),
        entity_id VARCHAR(255),
        payload JSONB,
        created_at TIMESTAMP DEFAULT NOW()
      );

      CREATE INDEX IF NOT EXISTS idx_event_log_correlation ON event_log(correlation_id);
      CREATE INDEX IF NOT EXISTS idx_event_log_type ON event_log(event_type);
      CREATE INDEX IF NOT EXISTS idx_orders_user ON orders(user_id);
      CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
      CREATE INDEX IF NOT EXISTS idx_analytics_event_name ON analytics_events(event_name);
      CREATE INDEX IF NOT EXISTS idx_analytics_created ON analytics_events(created_at);
    `);
    logger.info('Database tables initialized');
  } finally {
    client.release();
  }
}

// Main service class
class MessageProcessorService {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.isShuttingDown = false;
  }

  async start() {
    try {
      // Initialize database
      await initializeDatabase();

      // Connect to RabbitMQ
      this.connection = await amqp.connect(config.rabbitmq.url);
      this.channel = await this.connection.createChannel();

      // Set prefetch
      await this.channel.prefetch(config.rabbitmq.prefetch);

      // Assert queues
      await this.channel.assertQueue(config.rabbitmq.queue, {
        durable: true,
        arguments: {
          'x-dead-letter-exchange': '',
          'x-dead-letter-routing-key': config.rabbitmq.deadLetterQueue,
        },
      });

      await this.channel.assertQueue(config.rabbitmq.deadLetterQueue, {
        durable: true,
      });

      // Optionally assert exchange and bind
      try {
        await this.channel.assertExchange(config.rabbitmq.exchange, 'topic', { durable: true });
        await this.channel.bindQueue(config.rabbitmq.queue, config.rabbitmq.exchange, '#');
        logger.info('Exchange bound to queue', {
          exchange: config.rabbitmq.exchange,
          queue: config.rabbitmq.queue,
        });
      } catch (exchangeError) {
        logger.warn('Could not set up exchange binding, consuming directly from queue', {
          error: exchangeError.message,
        });
      }

      // Start consuming
      await this.channel.consume(config.rabbitmq.queue, (msg) => {
        if (msg && !this.isShuttingDown) {
          processMessage(msg, this.channel);
        }
      });

      logger.info('Message processor service started', {
        queue: config.rabbitmq.queue,
        prefetch: config.rabbitmq.prefetch,
      });

      // Handle connection errors
      this.connection.on('error', (err) => {
        logger.error('RabbitMQ connection error', { error: err.message });
        if (!this.isShuttingDown) {
          this.reconnect();
        }
      });

      this.connection.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ connection closed, attempting reconnect');
          this.reconnect();
        }
      });
    } catch (error) {
      logger.error('Failed to start service', { error: error.message, stack: error.stack });
      throw error;
    }
  }

  async reconnect() {
    const maxRetries = 10;
    let retryDelay = 1000;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        logger.info(`Reconnection attempt ${attempt}/${maxRetries}`);
        await new Promise((resolve) => setTimeout(resolve, retryDelay));
        await this.start();
        logger.info('Reconnected successfully');
        return;
      } catch (error) {
        logger.error(`Reconnection attempt ${attempt} failed`, { error: error.message });
        retryDelay = Math.min(retryDelay * 2, 30000); // Exponential backoff, max 30s
      }
    }

    logger.error('Max reconnection attempts reached, exiting');
    process.exit(1);
  }

  async shutdown() {
    this.isShuttingDown = true;
    logger.info('Shutting down message processor service...');

    try {
      if (this.channel) {
        await this.channel.close();
        logger.info('Channel closed');
      }
      if (this.connection) {
        await this.connection.close();
        logger.info('Connection closed');
      }
      await pool.end();
      logger.info('Database pool closed');
    } catch (error) {
      logger.error('Error during shutdown', { error: error.message });
    }

    logger.info('Service shut down gracefully');
    process.exit(0);
  }
}

// Create and start the service
const service = new MessageProcessorService();

// Graceful shutdown handlers
process.on('SIGINT', () => service.shutdown());
process.on('SIGTERM', () => service.shutdown());
process.on('uncaughtException', (error) => {
  logger.error('Uncaught exception', { error: error.message, stack: error.stack });
  service.shutdown();
});
process.on('unhandledRejection', (reason) => {
  logger.error('Unhandled rejection', { reason: String(reason) });
});

// Start the service
service.start().catch((error) => {
  logger.error('Fatal error starting service', { error: error.message });
  process.exit(1);
});

module.exports = { MessageProcessorService, messageHandlers, validateMessage, config };